import requests

def test_view_performance_review_with_invalid_id_format():
    base_url = 'http://localhost:8000'
    headers = {'Authorization': 'Bearer <valid_admin_token>'}

    invalid_ids = ['', '@#$%', '../../etc/passwd', 'pr_001_extra_long_id_string_overflow']

    for invalid_id in invalid_ids:
        response = requests.get(
            f'{base_url}/api/performance-reviews/{invalid_id}',
            headers=headers
        )
        assert response.status_code == 400
        data = response.json()
        assert 'error' in data or 'message' in data or 'errors' in data
